      "scene_id": "EP21_TOKYO_STATION_SHINKANSEN_GATE",
      "scene_name": "东京站新干线检票口前",
      "dialogue": [
        {
          "speaker": "佐藤美咲",
          "text": "健一叔叔会的。他托我带你走，远离开链条。小樱，你是希望，别怕。",
          "purpose": "回应樱子对健一的担忧，明确健一托付美咲带她离开旧链条，并强化希望。",
          "source": "onscreen",
          "listener": "佐藤樱子"
        }
      ],
      "narration": [],
      "subtitle": [
        "健一叔叔会的。他托我带你走，远离开链条。小樱，你是希望，别怕。"
      ],
